let raw = $json.text || $json.output || $json.response || '';

// Remove markdown code fences if present
if (typeof raw === 'string') {
  raw = raw.trim();

  if (raw.startsWith('```json')) {
    raw = raw.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');
  } else if (raw.startsWith('```')) {
    raw = raw.replace(/^```\s*/i, '').replace(/\s*```$/i, '');
  }
}

const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;

return {
  json: {
    customer_phone: $('Webhook').first().json.body?.From || $('Webhook').first().json.From || '',
    customer_message: $('Webhook').first().json.body?.Body || $('Webhook').first().json.Body || '',
    customer_name: $('Webhook').first().json.body?.ProfileName || $('Webhook').first().json.ProfileName || 'Customer',
    category: parsed.category || 'general',
    order_id: (parsed.order_id || '').toUpperCase(),
    summary: parsed.summary || '',
    needs_human: parsed.needs_human || false,
    channel: 'Whatsapp',
    received_at: new Date().toISOString(),
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, we could not find a matching order from your message. Please reply with your correct order ID so our team can assist you.`,
    final_status: 'Escalated',
    resolution_type: 'Human Review',
    escalated: true,
    channel: 'Whatsapp',
    received_at: new Date().toISOString(),
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, your order ${$json.order_id} is currently ${$json.order_status}. Tracking number: ${$json.tracking_number}. Carrier: ${$json.carrier}.`,
    final_status: 'Resolved',
    resolution_type: 'Auto Reply',
    escalated: false,
  }
};

const eligible = Boolean($json.refund_eligible);

return {
  json: {
    ...$json,
    reply_text: eligible
      ? `Hello ${$json.customer_name}, your refund request for order ${$json.order_id} has been received and is eligible for processing.`
      : `Hello ${$json.customer_name}, your refund request for order ${$json.order_id} has been received. A support agent will review it shortly.`,
    final_status: eligible ? 'Refunded' : 'Escalated',
    resolution_type: eligible ? 'Auto Refund' : 'Human Review',
    escalated: eligible ? false : true,
    refund_amount: eligible ? $json.amount_paid : 0,
    auto_resolved_flag: eligible ? 1 : 0,
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, we’ve received your report about the wrong item for order ${$json.order_id}. A human support agent will review it shortly.`,
    final_status: 'Escalated',
    resolution_type: 'Human Review',
    escalated: true,
    refund_amount: 0,
    auto_resolved_flag: 0,
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, your order ${$json.order_id} is currently delayed. Current status: ${$json.order_status}. Tracking number: ${$json.tracking_number}. Carrier: ${$json.carrier}. A support agent will continue to monitor it.`,
    final_status: 'Waiting',
    resolution_type: 'Manual Follow-up',
    escalated: true,
    refund_amount: 0,
    auto_resolved_flag: 0,
  }
};

const eligible = Boolean($json.return_eligible);

return {
  json: {
    ...$json,
    reply_text: eligible
      ? `Hello ${$json.customer_name}, your return request for order ${$json.order_id} has been received. Our support team will guide you through the next steps shortly.`
      : `Hello ${$json.customer_name}, your return request for order ${$json.order_id} has been received. A support agent will review your eligibility and contact you shortly.`,
    final_status: 'Escalated',
    resolution_type: 'Manual Follow-up',
    escalated: true,
    refund_amount: 0,
    auto_resolved_flag: 0,
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, thank you for contacting support. Your request has been received and a support agent will review it shortly.`,
    final_status: 'In Progress',
    resolution_type: 'Manual Follow-up',
    escalated: true,
    refund_amount: 0,
    auto_resolved_flag: 0,
  }
};

return {
  json: {
    ...$json,
    reply_text: `Hello ${$json.customer_name}, we’ve received your message and a human support agent will review it shortly.`,
    final_status: 'Escalated',
    resolution_type: 'Human Review',
    escalated: true,
    refund_amount: 0,
    auto_resolved_flag: 0,
  }
};
